import{_ as e,c as t,o as p,ae as r}from"./chunks/framework.BvcDoAct.js";const l=JSON.parse('{"title":"HAYATO (MAZZEL)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/18_HAYATO.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/18_HAYATO.md"}'),A={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/18_HAYATO.md"};function o(S,a,M,n,h,E){return p(),t("div",null,[...a[0]||(a[0]=[r('<p>Talk about BMSG - 18</p><h1 id="hayato-mazzel" tabindex="-1">HAYATO (MAZZEL) <a class="header-anchor" href="#hayato-mazzel" aria-label="Permalink to &quot;HAYATO (MAZZEL)&quot;">​</a></h1><h3 id="喜欢hayato所喜欢之物的人有很多-——社长的一句话让我能够不再犹豫地表达自己" tabindex="-1">“喜欢HAYATO所喜欢之物的人有很多”——社长的一句话让我能够不再犹豫地表达自己 <a class="header-anchor" href="#喜欢hayato所喜欢之物的人有很多-——社长的一句话让我能够不再犹豫地表达自己" aria-label="Permalink to &quot;“喜欢HAYATO所喜欢之物的人有很多”——社长的一句话让我能够不再犹豫地表达自己&quot;">​</a></h3><p><em>HAYATO：2005年1月1日出生，东京都出身</em><br><br><br> ————HAYATO，你至今从SKY-HI那里听过、最让你印象深刻的一句话是什么？</p><p>是在MAZZEL纪录片《Maze to Parade》中，社长对我说的那句：“会喜欢HAYATO所喜欢之物的人有很多哦。”我以前常常因为像女孩舞这类自己喜欢的东西得不到认可而烦恼，但自从听到这句话之后，就能够毫不犹豫地表达自己的“喜欢”了。无论是《Parade》的服装造型，还是周边商品的创意，我也都把这些想法融入到了MAZZEL的活动中。</p><p>————最近听说MAZZEL成员和SKY-HI一起相处的时间变多了。</p><p>是的！在巡演随行的时候，我们一起待的时间很长，而且首次的Arena公演，社长两天也都亲自到场支持。大家一起去社长家做客的机会也变多了，能够轻松聊天的时间增加了，我很开心。</p><h3 id="再拉近三层关系-的要求-让成员间建立起彼此信赖的关系" tabindex="-1">“再拉近三层关系”的要求，让成员间建立起彼此信赖的关系 <a class="header-anchor" href="#再拉近三层关系-的要求-让成员间建立起彼此信赖的关系" aria-label="Permalink to &quot;“再拉近三层关系”的要求，让成员间建立起彼此信赖的关系&quot;">​</a></h3><p>————MAZZEL在2024年经历了首次巡演和首次Arena公演，感觉实现了飞跃式的成长。SKY-HI给了你们什么样的建议呢？</p><p>今年巡演时，社长给了我们一个课题：“让8位成员的关系再拉近三个阶段”。我们原本关系就很好，但通过增加成员之间的对话、私下也更频繁地一起出去玩，不知不觉间建立起了非常能够彼此信赖的关系。我在演出中带动观众气氛这方面不太擅长，更擅长和MUZE（粉丝）进行交流。所以自己做不到的部分就由其他成员来补足，彼此支撑，这样的关系是在巡演期间逐渐形成的，我觉得这也促成了我们的成长。</p><p>————在BMSG的艺人中，你的角色给人感觉是很好的“调味剂”。</p><p>确实是比较少见的类型（笑）。我觉得这是我的一个优势，今后也想通过和粉丝多多沟通，把这一点继续放大。社长也对我说过：“HAYATO在舞台上很擅长和粉丝沟通，希望今后也能继续保持。”能被看到这样的细节让我很感动，也增强了自信。</p><p>————你特别尊敬SKY-HI的哪些地方？</p><p>当然他的人格我也很尊敬，但我尤其尊敬他在现场演出中的表现方式。去看社长的演出时，我觉得他对表情的运用以及把观众带入自己世界观的能力都非常惊人。MC的时候会很可爱地和粉丝互动，但一旦歌曲开始，就能完整地构建出属于SKY-HI的世界。我当时就强烈地想：“MAZZEL也想做出这样的演出。”尤其是在《Tiger Style》中，社长兼具帅气与可爱的那种反差，真的很让人着迷。</p><p>————BMSG总部大楼建成、工作人员也增加，公司正经历快速变化。你和公司内其他艺人是如何交流的？</p><p>我在BMSG里算是数一数二的怕生类型（笑）。而且我也不太会去大家常去的公司内部桑拿，所以大楼建成后交流明显变多这种感觉倒是没有……不过，每年的“BMSG FES”确实能让我们加深交流。我觉得能通过这样的活动拉近彼此距离，是BMSG独有的特色，而且像把成员打乱重新组成限定组合的做法，在别的事务所也很少见，很新颖，我也很喜欢。去年是分成两队，今年分成了三队，因为每队人数变少了，和队内成员的交流也更加深入。我在BMSG MARINE，和队长Aile The Shota聊得比较多，现在已经是可以依赖的哥哥了！</p><h3 id="通过-bmsg-fes-重新发现成员的魅力" tabindex="-1">通过“BMSG FES”重新发现成员的魅力 <a class="header-anchor" href="#通过-bmsg-fes-重新发现成员的魅力" aria-label="Permalink to &quot;通过“BMSG FES”重新发现成员的魅力&quot;">​</a></h3><p>————你和Shota平时会有怎样的交流？</p><p>我很喜欢Shota的音乐性，而且他人真的非常温柔。在《THE FIRST》的时候，他被大家称为“像妈妈一样的存在”，我非常能理解。他来看MAZZEL巡演时会对我说“你唱得很好！”；在“BMSG FES”里，BMSG MARINE表演结束后，他也会跑过来只说一句话就离开，既很帅又很有趣。看到他和别人打打闹闹的时候，我也会羡慕，忍不住想“真好啊，我也想加入进去（笑）”。</p><p>————看得出你真的很喜欢他。在“BMSG FES”中也看了其他艺人的演出，应该受到了不少刺激吧？</p><p>是的。尤其是能在其他舞台上看到MAZZEL成员的表演让我很开心。因为在同一个组合里，其实很难客观地看待彼此的舞台。看到成员们努力的样子，我感到很自豪，也重新发现了“原来他还有这样的魅力”。BMSG GAIA的RAN和EIKI给我留下了特别深的印象。尤其是EIKI，在MAZZEL里很少看到他那么有冲劲的一面，非常新鲜。</p><p>————你所在的BMSG MARINE舞台感觉如何？</p><p>可以说正因为有edhiii boi，MARINE这个组合才得以成立，他绝对是关键人物。我从没见过他把情绪释放得那么强烈，真的太棒了！每次听到他的part都会让我忍不住想掉眼泪。</p><p>————通过这次活动也更深刻感受到BMSG的魅力了吧。作为其中一员，你觉得它的强项是什么？</p><p>我觉得是所有人的表演能力都很高。没有人会对提升技术有所妥协，每个人都会不断努力，能够在这样的环境中一起创造好的作品，我觉得非常幸福。大家彼此刺激、互相支撑、一起向更高目标努力的这种感觉我也很喜欢。虽然每个人的个性和音乐性都不同，但努力的方向是一致的。彼此切磋琢磨、整个公司团结一心向前，这种氛围非常强烈。无论是作为MAZZEL的一员，还是作为BMSG的一员，对我来说都是一种骄傲。</p><p>————2025年，继BE:FIRST、MAZZEL之后，第三个男子组合将通过选秀《THE LAST PIECE》诞生。你有什么感想？</p><p>首先，我非常高兴曾在《MISSIONx2》中一起努力过的KANON终于要出道了。一直以来，在公司内部的团体中，MAZZEL算是最新人，但我们也不想输，希望能一起努力。今后也想让MAZZEL的风格更加鲜明，成为独一无二的组合。在《THE LAST PIECE》迎来最终阶段之前，我也希望自己能成长为更加出色的艺人。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>他能够从与我不同的文化中汲取养分并带来新的输入，是对BMSG来说非常宝贵的人才。</p><p>他也有持续努力的习惯，每一场演出都能有具体的成长，而且具备能够把“挥棒”贯彻到底的力量，所以哪怕只错过两三场演出，也常常会觉得他像换了一个人。</p><p>他本身认真踏实的性格也非常可靠，但其实他也是最年少的成员。我认为，当他真正体会到这里是一个可以信任他人、适度依赖、让自己放松下来的“留白之地”时，还会迎来更大的蜕变，而且那一天已经在慢慢靠近了。当然，“依赖”“信任”和“逃避”看似相似却完全不同，要学会区分并掌握它们，本身也是一项不小的挑战。</p></blockquote>',28)])])}const s=e(A,[["render",o]]);export{l as __pageData,s as default};
